package github.chains;

import spoon.Launcher;
import spoon.reflect.CtModel;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.code.CtLiteral;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;

/**
 * Generic Spoon transformation rule to fix breaking API changes in dependencies.
 * This rule specifically addresses changes in ActionProxyFactory API from Struts2.
 * 
 * Breaking change pattern:
 * Old: createActionProxy(String actionName, String namespace, String methodName, Map params)
 * New: createActionProxy(String actionName, String namespace, String methodName, Map params, boolean executeResult, boolean cleanupContext)
 * 
 * This transformation adds the two missing boolean parameters (executeResult, cleanupContext) to all invocations
 * of createActionProxy with the old signature.
 * 
 * Usage: java -cp <classpath> github.chains.Main <source_directory>
 */
public class Main {
    public static void main(String[] args) {
        // Check if arguments are provided
        if (args.length < 1) {
            System.err.println("Usage: java -cp <classpath> github.chains.Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create a Spoon launcher
        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "/transformed");

        // Process the code
        CtModel model = launcher.buildModel();

        // Find all invocations of createActionProxy with 4 parameters
        List<CtInvocation<?>> invocations = model.getElements(new TypeFilter<>(CtInvocation.class));

        for (CtInvocation<?> invocation : invocations) {
            CtExecutableReference<?> executableRef = invocation.getExecutable();

            // Check if this is an invocation of createActionProxy in ActionProxyFactory
            if (executableRef != null && "createActionProxy".equals(executableRef.getSimpleName())) {
                // Check if it has exactly 4 parameters (the old signature)
                if (invocation.getArguments().size() == 4) {
                    // Check if the method is from ActionProxyFactory (by type)
                    // We need to check if the declaring type is ActionProxyFactory or a subclass
                    CtType<?> declaringType = executableRef.getDeclaringType();
                    if (declaringType != null && 
                        ("ActionProxyFactory".equals(declaringType.getSimpleName()) || 
                         declaringType.getQualifiedName().endsWith(".ActionProxyFactory"))) {

                        // Add the two missing boolean parameters: executeResult = true, cleanupContext = false
                        invocation.addArgument(launcher.getFactory().Code().createLiteral(true));
                        invocation.addArgument(launcher.getFactory().Code().createLiteral(false));

                        System.out.println("Fixed createActionProxy invocation: " + invocation.toString());
                    }
                }
            }
        }

        // Generate the transformed code
        launcher.writeProcessedSourceFiles();
        System.out.println("Transformation completed. Output written to: " + sourceDirectory + "/transformed");
    }
}

